using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddHostedService<ModelTrainerService>();

var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapPost("/api/predict", (
    PredictionEnginePool<TicketInput, TicketPrediction> pool,
    TicketPredictionRequest request) =>
{
    var input = new TicketInput
    {
        Subject = request.Subject,
        Description = request.Description,
        Priority = request.Priority
    };

    var prediction = pool.Predict(input);

    return Results.Ok(new
    {
        prediction.Category,
        Confidence = prediction.Score.Max(),
        Scores = new
        {
            Billing = prediction.Score.ElementAtOrDefault(0),
            General = prediction.Score.ElementAtOrDefault(1),
            Technical = prediction.Score.ElementAtOrDefault(2)
        }
    });
